document.addEventListener("DOMContentLoaded",(function(){let e=document.querySelectorAll("[class*='animate-']"),t=Array.prototype.slice.call(e),n=!1;if(t.length>0){window.addEventListener("scroll",(function e(){if(n)return;n=!0,setTimeout(()=>{for(let e=0;e<t.length;e++){let n=t[e];n.getBoundingClientRect().top-window.innerHeight/1.75<=0&&(n.classList.add("_active"),t.splice(e,1),e-=1)}0==t&&window.removeEventListener("scroll",e),n=!1},100)}))}})),document.addEventListener("DOMContentLoaded",(function(){const e=document.querySelectorAll(".tabs__tabs");if(e.length)for(let t=0;t<e.length;t++){const n=e[t].querySelectorAll(".tabs__item");for(let e=0;e<n.length;e++){const t=n[e];t.querySelector(".tabs__item-button").addEventListener("click",(function(){for(let e=0;e<n.length;e++){n[e].classList.remove("_active")}t.classList.add("_active")}))}}}));